scwin.f_ReqFieldChk = async function () {
  //필수입력항목 체크
  // var passwd = "<%=userDto.getDecPasswd()%>";
  var passwd = scwin.passwd;
  // var oldPasswd = document.all.txt_oldPasswd.value.trim();
  var newPasswd = txt_newPasswd.getValue().trim();
  var confirmPasswd = txt_confirmPasswd.getValue().trim();
  if (newPasswd == "") {
    $c.gus.cfAlertMsg($p, MSG_LO_ERR_002);
    return false;
  }
  if (confirmPasswd == "") {
    $c.gus.cfAlertMsg($p, MSG_LO_ERR_003);
    return false;
  }
  if (newPasswd != confirmPasswd) {
    $c.gus.cfAlertMsg($p, MSG_LO_ERR_005);
    return false;
  }
  let passCheckVal = await scwin.f_passwordCheck(txt_userId.getValue(), newPasswd);
  if (!passCheckVal) {
    txt_newPasswd.focus();
    return false;
  }
  if (passwd == newPasswd) {
    $c.gus.cfAlertMsg($p, MSG_LO_ERR_004);
    return false;
  }
  return true;
};
scwin.f_passwordCheck = async function (vUserId, vPassword) {
  var iLen = vPassword.length;
  var engCnt = $c.gus.cfisEnglishCnt($p, vPassword);
  var numCnt = $c.gus.cfisNumberCnt($p, vPassword);
  if ($c.gus.cfnumChainChk($p, vPassword)) {
    $c.win.alert($p, "비밀번호는 연속 또는 동일한  숫자 3자리 이상  사용할 수 없습니다.");
    return false;
  }
  if (iLen < 10) {
    $c.win.alert($p, "비밀번호는 10자리 이상이어야 합니다.");
    return false;
  }
  let patternChk = await scwin.f_specialPatternCheck(vPassword);
  if (!patternChk) {
    $c.win.alert($p, "비밀번호는 특수문자가 포함되어야 합니다.");
    return false;
  }
  if (engCnt == 0 || numCnt == 0) {
    $c.win.alert($p, "비밀번호는 영어+숫자+특수문자 조합이어야 합니다.");
    return false;
  }
  if (vUserId == vPassword) {
    $c.win.alert($p, "사용자ID를 비밀번호로 사용할  수  없습니다.");
    return false;
  }
  return true;
};

//특수문자 입력체크
scwin.f_specialPatternCheck = function (vPassword) {
  var special_pattern = /[`~!@#$%^&*|\\\'\";:\/?]/gi;
  if (special_pattern.test(vPassword) == true) {
    // alert('특수문자가 입력되었습니다.');
    return true;
  } else {
    return false;
  }
};
